import{_ as s,o as a,c as t,ae as e}from"./chunks/framework.Czhw_PXq.js";const r="/assets/image1.BJX9NP-0.png",i="/assets/image2.CRMHzHfV.png",c="/assets/image3.Cp8QEgY_.png",m="/assets/image4.D_JTxN2k.png",o="/assets/image5.BrJH6YL4.png",l="/assets/image6.nfl9x8KJ.png",n="/assets/image7.TsLKBXf2.png",g="/assets/image8.w8-B33_9.png",_="/assets/image9.DSPeqsJf.png",f="/assets/image10.HhYYom90.png",x="/assets/image11.BfO_puFz.png",d="/assets/image12.BA3J0yPl.png",b="/assets/image13.BYLdEBO0.png",u="/assets/image14.CtxXgmkZ.png",h="/assets/image15.rVimRNUV.png",O="/assets/image16.Dy0shiXL.png",k="/assets/image17.BzdfUkkf.png",v="/assets/image18.DfNMkXXS.png",B="/assets/image19.Cr46-7Xv.png",w="/assets/image20.eSGkjs0w.png",y="/assets/image21.62x61fpp.png",j="/assets/image22.Blt1aGmY.png",C="/assets/image23.Boy3A_Ro.png",A="/assets/image24.UQbnOQ7K.png",S="/assets/image25.rXxUexeE.png",X="/assets/image26.BDnDkO6N.png",D="/assets/image27.C_EZQnuA.png",N="/assets/image28.Bn0RHAbT.png",P="/assets/image29.BHC2-5S_.png",V=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"0413lab.md","filePath":"0413lab.md"}'),T={name:"0413lab.md"};function U(J,p,M,q,E,G){return a(),t("div",null,[...p[0]||(p[0]=[e('<p>0413 实验报告</p><p>一、loop</p><p>（1）原版</p><p>普通的使用寄存器和栈来回移动（体现在非常多的mov）的保守做法。</p><p>For和while高度相似，都是按照while的原代码逻辑进行的汇编，也就是拆散了原来for写在一起的i++，放到了和while一样的后面。</p><p>如图为for汇编码的核心部分，我加了-M把源码放进去对比，可以看到出现了两次，其实第一次只是在初始化，并且一开始没有做i++的事情，而是在第一次循环结束，也就是116a的地方才做i++，这点编译器已经做了顺序的调整。</p><p><img src="'+r+'" alt=""></p><p>Do while</p><p>略有不同，首先一开始多了一个判断，在判断后只需要小跳（11ca到11d3）而不需要像for和while的大跳（如上图1162到116e）</p><p>整体给人感觉比较流畅，但可能不是cpu最想看到的样子</p><p><img src="'+i+'" alt=""></p><p>总结：原版for和while都用了50byte，dowhile用61byte，略多。</p><p>（2）O1</p><p>做了很多优化，首先整体和原版对比：</p><p>1、test和jle结合，充分使用CPU Flags，从而判断n是否等于0，而又不直接和0做比较，相比原版n=0也要进入循环体，在这个情况节省了很多时间</p><p>2、从b到1a，正常做法，但是与栈无关了，而是直接在寄存器里运算，省去了很多mov</p><p><img src="'+c+'" alt=""></p><p>3、在1c处，使用jne会比jle要快很多（判断不等于），而第8行给n+1也是为这一点做准备</p><p>再横向比较：</p><p>1、For和while的O1完全相同，均为40字节</p><p><img src="'+m+'" alt=""></p><p>2、do while只有33字节，一开始就赋值sum=0省去了mov的5byte和jmp的2byte</p><p>main函数的差异</p><p>1、O1相比原版未见rbp、rsp</p><p>2、原版遵循保守逻辑，所有的栈和寄存器之间的运输必须通过传统中转站eax和rax，</p><p>这在O1得到了极大优化，省了很多步骤</p><p>3、O1触发了一个安全系统，由printf变为了printf chk，在保证安全的同时其实也增多了一些定义，如安全级别的&quot;2&quot;，且因为2是存在edi里面的，每次要重复再把a移动过去</p><p><img src="'+o+'" alt=""></p><p>4、原版反复使用%rip自动寻址这一点在O1只做了一次</p><p>下图分别是原版和O1</p><p><img src="'+l+'" alt=""></p><p>（3）O2</p><p>1、引入了xor，由于任何东西和自己异或都是0，更快的清零（xor只要2字节，而把0mov给一个寄存器要5字节）<br> 可以看到这里要对sum赋值0，机器码只有31 d2，而mov是b8 00 00 00 00，因为要出现一个16进制表示的32位整数</p><p><img src="'+n+'" alt=""></p><p>2、引入和1的and通过尾数判断奇偶，便于在循环中两个两个的加，加快速度</p><p><img src="'+g+'" alt=""></p><p>3、引入了lea作为加法器，由于lea作用在AGU（地址生成单元）而非ALU（算术逻辑单元），从而实现了指令级的并行；同时在AGU层面的加法与乘法的结合效率更高</p><p><img src="'+_+'" alt=""></p><p>4、引入了大量用于对齐的语句，如25、36、3d、45、4c</p><p><img src="'+f+'" alt=""></p><p>具体不太理解，但如果是ret之后cpu永远不会执行到的地方，就用零填充；而如果是在可能连续执行代码块或函数之间，则用真指令如NOP，再根据不同字节的需求加前缀</p><p>后续横向大致相同</p><p>（4）O3</p><p>采用了更激进的打法，引入了128位XMM寄存器，一次性把4个整数放在一起做加法，大部分很新的代码都是为了给这个服务</p><p><img src="'+x+'" alt=""></p><p>1、cmp和jbe，在把n和9做对比，太小就没必要进入XMM的计算流程</p><p><img src="'+d+'" alt=""></p><p>2、pxor用于对xmm0寄存器全部清零，movdqa用于加载128位的数据到xmm中，paddd为并行加法，可以把4个整数成对相加，最后再用shr调整应该循环的次数为原来的1/4</p><p><img src="'+b+'" alt=""></p><p>3、结合使用 psrldq和paddd进行内部对折合并，并提取到普通寄存器，最后处理无法被4整除的剩余部分</p><p>总结：适合n较大的时候，可以减少时间到约1/4.</p><p>二、switch-case两个版本的对比</p><p>（1）跳转表的使用</p><p>跳转表本身是当switch-case较多时编译器的一种优化方式，通过生成一个表<br> 拆解表的意思：</p><p>1、84f1ffff到b0f1ffff 是case0到case4目标代码地址和跳转表基地址的相对偏移量</p><p><img src="'+u+'" alt=""></p><p>2、78一直到00 是printf字符串对应的ASCII码（这一部分与跳转表无关）</p><p>这是switchcase函数的部分反汇编，首先115e和1162做了一个初步的跳转，如果x大于4，就直接default y=-1</p><p>其次我们要关注1167，这里计算rax（存的是x） * 4，这是一个附加的偏移量，很好理解，跳转表里每一个偏移量都是4byte，存在rdx里</p><p>然后是编译器如何计算出基地址 在116f 他将rip（指向下一个指令的地址，也就是0x1176）加上0xe8e，正好得到0x2004，并存在rax里</p><p>1176行非常关键，mov()的意思是把括号里的东西对应的地址对应的值取出来（类似解引用），并赋给eax，也就是说这里我们是要找0x2004+4x对应的地址，这个东西显然在rodata段，也就是要去看跳转表里的地址（并不是要加上0x2004和4x，只是要去找地址，每个case对应地址的偏移都已经提前算好了）</p><p>cltq是将32位eax拓展到64位rax</p><p>117b类似的读出2004，notrack jmp是指跳转到rax对应的一个地址</p><p><img src="'+h+'" alt=""></p><p>这个地址随着x的变化而变化，对应不同的case</p><p>总结：程序运行前先算好了跳转表的值（根据基地址0x2004和目的地）放到rodata段，然后正常运行程序，到switch的时候需要进行跳转，再分别进入不同的case</p><p>相比if-else的逻辑，在case数较多的时候，用跳转表的方式可以大大节省时间，用专业点的话来讲，就是时间复杂度由O（n）下降到O（1）</p><p>（2）有无break的对比</p><p><strong>有 break 的地方</strong>：A多了jmp，break</p><p><strong>没 break 的地方</strong>：没有jmp，直接进入下一个case</p><p>使用objdump在函数定义段显然可以看到：</p><p><img src="'+O+'" alt=""></p><p>三、函数</p><p>（1）caller与callee</p><p>1、6个参数与8个参数的对比</p><p>首先，只有6个寄存器（%rdi, %rsi, %rdx, %rcx, %r8, %r9）负责存这样的参数，剩余的都要在栈上排队，因此，在callee2和callee2对应的caller中，可以看到不同：</p><p>1192-11ae是相同的，callee只在对已经在寄存器里面的东西做文章（101-606）</p><p>11d9-11e4则是callee2多出来的，对放在栈中正偏移的部分做文章（707和808）</p><p>再仔细观察，callee2在caller中的调用部分多了两个push，作用是把707和808先压入栈中，且顺序是先808 再707</p><p><img src="'+k+'" alt=""></p><p><img src="'+v+'" alt=""></p><p>后续也是一样，在call之前，是从606到101倒着mov的，遵循<strong>后进先出</strong>原则，效率最大化</p><p><img src="'+B+'" alt=""></p><p>2、寄存器的分类</p><p>Caller saved registers: %rax、%rdi、%rsi、%r8、%r9、%r10、%r11、%rcx、%rdx</p><p>Callee saved registers: %rbx、%rbp、%r12、%r13、%r14、%r15</p><p>Caller的体现：在call完callee1之后存在rax中的返回值，迅速存到自己的栈中，因为rax后续还要给callee2用</p><p><img src="'+w+'" alt=""></p><p>callee的体现：</p><p><img src="'+y+'" alt=""></p><p><img src="'+j+'" alt=""></p><p>rbp在caller中用于指向自己的栈帧，但在callee中也要被用于指定局部变量的内存，所以这里需要先push备份rbp，最后再pop还原rbp，确保rbp进来什么样出去什么样</p><p>（2）fun_locals</p><p>1、fun1函数内部的入口与出口的呼应</p><p>1171减了128byte（这个0xffffffffffffff80就是补码形式的-128）来给这么多long和char腾出空间，在118d行加入了一个随机数，据资料得知，编译器开启了栈保护stack canary，如果缓冲区溢出这个数就会被覆盖掉，最后编译器再进行检查，如果数是一样的就正常输出，否则程序直接自杀</p><p><img src="'+C+'" alt=""></p><p>在结尾处首先进行了比对，如果e（等）就jump到125f，否则call1060然后程序GG</p><p>其次leave，即mov %rbp, %rsp 和 pop %rbp，相当于回收了128byte</p><p><img src="'+A+'" alt=""></p><p>2、fun2的一些实现</p><p><img src="'+S+'" alt=""></p><p>在处理short的时候使用了小一号的寄存器ax，并且对应的空间（注意0xc到0xa）也是2byte</p><p><img src="'+X+'" alt=""></p><p>前面在fun1的地方更是用了al更小一号的寄存器来存char的元素 1byte</p><p>3、fun1与fun2函数的比对</p><p>结论：Fun2简单很多，没有明显的栈开辟的操作，也没有使用stack canary，也没有使用leave，这主要是源于fun1的参数较多较大，尤其是有一个数组面临潜在的缓冲区溢出的风险。可见编译器是视情况而定的。</p><p>（3）factorial</p><p>1、O1的两种情况的对比</p><p>首先O1进行了一些和这个报告最一开始的O1类似的优化：</p><p>1）少用栈，直接在寄存器上做运算</p><p>2）分运用lea做加法</p><p>3）在for循环1172将n+1，后续118a比对jne提高效率</p><p>以及一些特点：</p><p>使用imul做整数乘法</p><p>差异：</p><p>1）rfac看似简单，实际上需要在11ab反复call，一旦call需要从头开始；</p><p><img src="'+D+'" alt=""></p><p>2）ifrac看似略复杂，实际上每次的jmp（1195到118c）只需要做较少的运算。</p><p><img src="'+N+'" alt=""></p><p>2、O3的两种情况的对比</p><p>1）横向对比O1</p><p>主要优化在连乘和对齐</p><p>test $0x1, %sil</p><p>sil是rsi寄存器的8位1字节，高效率完成奇偶的判定</p><p>2）O3的rfac</p><p>这里几乎是直接将递归变成了循环，没有出现自己call自己的命令</p><p><img src="'+P+'" alt=""></p><p>其核心部分12f8到1306与循环高度相似，唯一区别是O3的ifac又进行了两个数的连乘，而查资料了解到，编译器在优化递归的时候会相对保守，倾向于不使用连乘。</p><p>本次实验的最后总结：</p><p>我统共花了6个多小时完成第一个loop的理解</p><p>后续第二个和第三个加起来也用了6个小时左右</p><p>一开始我的方向有点问题，试图看懂每一行反汇编码</p><p>后续我提升了速度，但仍然较慢，并且我确实觉得大部分的反汇编码并不显然，需要反复琢磨。虽然本实验主要目的是理解objdump怎么用，但我也学到了很多程序优化的时候的方法和思路，试着像cpu一样思考。</p>',133)])])}const Y=s(T,[["render",U]]);export{V as __pageData,Y as default};
